- "ocean of threads" metaphorically refers to the collection or database of threads, implying a vast and diverse network of discussions or content;
- "most stories (threads) to their name" refers to the user who has authored the highest number of threads.

sql:
SELECT DISTINCT u.user_id, u.username, u.profile_picture
FROM users u
WHERE u.user_id IN (
    SELECT t.author_id
    FROM threads t
) AND u.user_id IN (
    SELECT tr.author_id
    FROM thread_replies tr
);

SELECT thread_id, COUNT(category_id) AS Total_Categories
FROM thread_categories
GROUP BY thread_id;

SELECT AVG(thread_count) as avg_threads_per_user
FROM (
  SELECT author_id, COUNT(*) as thread_count
  FROM threads
  GROUP BY author_id
);

SELECT DISTINCT u.username 
FROM users u 
JOIN threads t ON u.user_id = t.author_id;

